        }

function calcExchange() {
            const base = parseFloat(document.getElementById('baseRate').value);
            const discount = parseFloat(document.getElementById('spreadDiscount').value) / 100;
            const usd = parseFloat(document.getElementById('usdAmount').value);

            if (isNaN(base) || isNaN(usd)) {
                alert('정확한 값을 입력해주세요.'); 
                return;
            }

            // 일반적인 은행 현찰 수수료율 1.75% 가정
            const spreadRate = 0.0175;
            const feePerDollar = base * spreadRate;
            const discountedFee = feePerDollar * (1 - discount);
            const finalExchangeRate = base + discountedFee;
            const totalKrw = finalExchangeRate * usd;

            document.getElementById('finalRate').textContent = finalExchangeRate.toFixed(2); 
            document.getElementById('finalKrw').textContent = Math.floor(totalKrw).toLocaleString(); 
            document.getElementById('resultArea').style.display = 'block'; 
        }

